import React, { useContext, useEffect, useRef, useState, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { AuthContext } from '../contexts/AuthContext';
import { io } from 'socket.io-client';
import { Chess } from 'chess.js';
import ChessBoard from '../components/ChessBoard';
import Bracket from '../components/Bracket';
import ResultModal from '../components/ResultModal';
import MatchOptions from '../components/MatchOptions';
import MoveHistory from '../components/MoveHistory';
import GameReview from '../components/GameReview';
import MatchSettings from '../components/MatchSettings';

const API_URL = 'http://localhost:3001';

export default function RoomPage() {
  const { roomId } = useParams();
  const navigate = useNavigate();
  const { user, refreshUser } = useContext(AuthContext);

  const socketRef = useRef(null);
  const matchRef = useRef(null);

  const [room, setRoom] = useState(null);
  const [match, setMatch] = useState(null);
  const [bracket, setBracket] = useState(null);
  const [fen, setFen] = useState('rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1');
  const [status, setStatus] = useState('Connecting...');
  const [gameStatus, setGameStatus] = useState('waiting');
  const [whitePlayer, setWhitePlayer] = useState(null);
  const [blackPlayer, setBlackPlayer] = useState(null);
  const [currentPlayerColor, setCurrentPlayerColor] = useState(null);
  const [boardOrientation, setBoardOrientation] = useState('white');
  const [moveHistory, setMoveHistory] = useState([]);
  const [timerData, setTimerData] = useState(null);
  const [resultData, setResultData] = useState(null);
  const [activeTab, setActiveTab] = useState('board');
  const [spectatorCount, setSpectatorCount] = useState(0);
  const [drawOfferPending, setDrawOfferPending] = useState(false);
  const [drawOfferReceived, setDrawOfferReceived] = useState(false);
  const [floatingEmoji, setFloatingEmoji] = useState(null);
  const [previewIndex, setPreviewIndex] = useState(-1);
  const [lastMove, setLastMove] = useState(null);
  const [showGameReview, setShowGameReview] = useState(false);
  const [reviewData, setReviewData] = useState(null);
  const [showSettings, setShowSettings] = useState(false);
  const [moveTimeoutMs, setMoveTimeoutMs] = useState(30000);

  // Settings
  const [settings, setSettings] = useState(() => {
    try {
      const saved = localStorage.getItem('chess-settings');
      return saved ? JSON.parse(saved) : {};
    } catch { return {}; }
  });

  // Current match moves as SAN (for review)
  const moveSansRef = useRef([]);

  // Compute preview FEN
  const getPreviewFen = useCallback(() => {
    if (previewIndex === -1 || moveHistory.length === 0) return null;
    try {
      const game = new Chess();
      for (let i = 0; i <= previewIndex && i < moveHistory.length; i++) game.move(moveHistory[i]);
      return game.fen();
    } catch { return null; }
  }, [previewIndex, moveHistory]);

  const displayFen = previewIndex === -1 ? fen : (getPreviewFen() || fen);

  useEffect(() => {
    if (!roomId) return;
    const userId = user?.id;

    if (!socketRef.current) socketRef.current = io(API_URL);
    const socket = socketRef.current;
    socket.removeAllListeners();

    if (userId) {
      socket.emit('identify', { userId });
      socket.emit('joinRoom', { roomId, userId });
    } else {
      socket.emit('spectateRoom', { roomId });
    }

    socket.on('roomUpdate', (r) => {
      setRoom(r);
      if (r.status === 'waiting') setStatus(`Waiting for players (${r.players?.length}/${r.maxPlayers})`);
      else if (r.status === 'ongoing') setStatus('Tournament in progress');
      else if (r.status === 'completed') setStatus('Tournament completed');
    });

    socket.on('bracketUpdate', (data) => setBracket(data));

    socket.on('matchStarted', (data) => {
      if (data.roomId !== roomId) return;
      const matchData = { ...data };
      setMatch(matchData);
      matchRef.current = matchData;
      setFen(data.fen || 'rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1');

      // Restore moves from payload if rejoining
      const existingMoves = data.moves || [];
      const sans = existingMoves.map(m => m.san || m).filter(Boolean);
      setMoveHistory(sans);
      moveSansRef.current = sans;

      // Set last move from existing moves
      if (existingMoves.length > 0) {
        const lastM = existingMoves[existingMoves.length - 1];
        if (lastM.from && lastM.to) setLastMove({ from: lastM.from, to: lastM.to });
      } else {
        setLastMove(null);
      }

      setPreviewIndex(-1);
      setDrawOfferPending(false);
      setDrawOfferReceived(false);
      setResultData(null);
      setReviewData(null);

      if (data.timeControl) setMoveTimeoutMs(data.timeControl * 60 * 1000);

      if (userId && data.whitePlayerId === userId) {
        setCurrentPlayerColor('white');
        setBoardOrientation('white');
      } else if (userId && data.blackPlayerId === userId) {
        setCurrentPlayerColor('black');
        setBoardOrientation('black');
      } else {
        setCurrentPlayerColor(null);
      }

      setWhitePlayer(data.whitePlayer || { id: data.whitePlayerId, username: 'White' });
      setBlackPlayer(data.blackPlayer || { id: data.blackPlayerId, username: 'Black' });
      setGameStatus('playing');
      setStatus(`Round ${data.round || 1} — Match started`);
    });

    socket.on('gameReady', ({ matchId }) => {
      if (matchRef.current?.matchId === matchId) {
        setStatus('Game started! Make your move.');
      }
    });

    socket.on('timerStart', (data) => {
      if (matchRef.current?.matchId === data.matchId) {
        setTimerData(data);
      }
    });

    socket.on('moveMade', ({ matchId, fen: newFen, san, from, to, captured, inCheck }) => {
      if (matchRef.current?.matchId === matchId) {
        setFen(newFen);
        if (san) {
          setMoveHistory((prev) => [...prev, san]);
          moveSansRef.current.push(san);
        }
        setPreviewIndex(-1);
        if (from && to) setLastMove({ from, to });
      }
    });

    socket.on('matchEnded', (data) => {
      if (matchRef.current?.matchId === data.matchId) {
        setGameStatus('finished');
        setTimerData(null);
        setDrawOfferPending(false);
        setDrawOfferReceived(false);

        const winnerId = data.winner?.toString();
        const isWinner = winnerId && userId && winnerId === userId;
        const isDraw = !data.winner && ['draw', 'stalemate', 'repetition', 'insufficient'].includes(data.reason);

        // Determine player color for review
        const playerColor = currentPlayerColor === 'white' ? 'w' : 'b';

        setReviewData(data.review || null);
        setResultData({
          isWinner,
          isDraw,
          winnerName: data.winnerName || (isWinner ? user?.username : isDraw ? null : 'Opponent'),
          reason: data.reason || 'checkmate',
          prize: data.prize || 0,
          eloChange: data.eloChange || null,
          newElo: data.newElo || null,
          review: data.review || null,
          playerColor,
          coachComment: data.coachComment || null,
        });

        setStatus(`Match ended — ${data.reason || 'Game over'}`);
        if (userId) refreshUser();
      }
    });

    socket.on('roomCompleted', (data) => {
      setRoom(data);
      setGameStatus('completed');
      setStatus('🏆 Tournament completed!');
      if (userId) refreshUser();
    });

    socket.on('invalidMove', (data) => console.warn('Invalid move:', data));
    socket.on('errorMsg', (msg) => console.error('Socket error:', msg));
    socket.on('forceLogout', () => navigate('/login'));
    socket.on('spectatorCount', ({ count }) => setSpectatorCount(count));

    socket.on('drawOffer', ({ matchId }) => {
      if (matchRef.current?.matchId === matchId) setDrawOfferReceived(true);
    });
    socket.on('drawDeclined', ({ matchId }) => {
      if (matchRef.current?.matchId === matchId) setDrawOfferPending(false);
    });
    socket.on('emojiReaction', ({ emoji, playerId }) => {
      if (playerId !== userId) {
        setFloatingEmoji(emoji);
        setTimeout(() => setFloatingEmoji(null), 2500);
      }
    });

    return () => {};
  }, [roomId]);

  useEffect(() => {
    return () => {
      if (socketRef.current) {
        socketRef.current.disconnect();
        socketRef.current = null;
      }
    };
  }, []);

  const handleMove = ({ from, to, promotion, san }) => {
    if (!matchRef.current || !currentPlayerColor) return;
    if (previewIndex !== -1) { setPreviewIndex(-1); return; }
    socketRef.current?.emit('makeMove', {
      roomId, matchId: matchRef.current.matchId, from, to, promotion, playerId: user.id,
    });
  };

  const handlePlayerReady = () => {
    if (!matchRef.current) return;
    socketRef.current?.emit('playerReady', {
      roomId, matchId: matchRef.current.matchId, playerId: user.id,
    });
  };

  const handleSetPremove = (premove) => {
    if (!matchRef.current) return;
    socketRef.current?.emit('setPremove', {
      roomId, matchId: matchRef.current.matchId, playerId: user.id, ...premove,
    });
  };

  const handleCancelPremove = () => {
    if (!matchRef.current) return;
    socketRef.current?.emit('cancelPremove', {
      roomId, matchId: matchRef.current.matchId, playerId: user.id,
    });
  };

  const handleResign = () => {
    if (!matchRef.current || !currentPlayerColor) return;
    socketRef.current?.emit('resign', { roomId, matchId: matchRef.current.matchId, playerId: user.id });
  };

  const handleDrawOffer = () => {
    if (!matchRef.current || !currentPlayerColor || drawOfferPending) return;
    setDrawOfferPending(true);
    socketRef.current?.emit('drawOffer', { roomId, matchId: matchRef.current.matchId, playerId: user.id });
  };

  const handleDrawResponse = (accepted) => {
    if (!matchRef.current) return;
    setDrawOfferReceived(false);
    socketRef.current?.emit('drawResponse', { roomId, matchId: matchRef.current.matchId, playerId: user.id, accepted });
  };

  const handleEmojiReaction = (emoji) => {
    socketRef.current?.emit('emojiReaction', { roomId, emoji, playerId: user.id });
    setFloatingEmoji(emoji);
    setTimeout(() => setFloatingEmoji(null), 2500);
  };

  const handleFlipBoard = () => setBoardOrientation((p) => (p === 'white' ? 'black' : 'white'));
  const handleMoveClick = (index) => setPreviewIndex(index);

  const handlePlayAgain = () => {
    // Navigate back to lobby for Play Now
    navigate('/');
  };

  const handleApplySettings = (newSettings) => {
    setSettings(newSettings);
  };

  const isSpectator = currentPlayerColor === null && match !== null;
  const currentPlayer = currentPlayerColor ? { color: currentPlayerColor, ...(currentPlayerColor === 'white' ? whitePlayer : blackPlayer) } : null;

  if (!roomId) {
    return (
      <div className="min-h-screen flex items-center justify-center px-4">
        <div className="card text-center max-w-md">
          <h2 className="text-2xl font-bold mb-4 text-white">No Room Selected</h2>
          <p className="text-slate-400 mb-6">Please join from lobby.</p>
          <button onClick={() => navigate('/')} className="btn-primary">Back to Lobby</button>
        </div>
      </div>
    );
  }

  const renderPlayerBadge = (p, idx) => {
    const isMe = (p._id || p).toString() === user?.id;
    return (
      <div key={p._id || idx} className={`flex items-center gap-3 p-2.5 rounded-xl transition-all ${isMe ? 'bg-chess-green/5 border border-chess-green/10' : 'bg-navy-900/30'}`}>
        <div className="relative">
          <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${isMe ? 'bg-gradient-to-br from-chess-green to-emerald-600 text-white' : 'bg-gradient-to-br from-slate-600 to-slate-700 text-slate-300'}`}>
            {(p.username || '?').charAt(0).toUpperCase()}
          </div>
          {p.online && <span className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-emerald-500 border-2 border-navy-900 rounded-full" />}
        </div>
        <div className="flex-1 min-w-0 flex items-center justify-between">
          <p className="text-sm font-medium text-white truncate">{p.username || 'Player'}</p>
          {p.online && <span className="text-[10px] text-emerald-400 font-medium ml-2">Online</span>}
        </div>
        {isMe && <span className="text-[10px] text-chess-green font-bold">YOU</span>}
      </div>
    );
  };

  return (
    <div className="min-h-[calc(100vh-64px)] bg-hero px-4 py-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="flex flex-wrap items-center justify-between gap-4 mb-6 animate-fade-in">
          <div>
            <div className="flex items-center gap-3 mb-1">
              <h1 className="text-2xl font-bold text-white">{room?.name || roomId}</h1>
              <span className={`badge ${room?.status === 'waiting' ? 'badge-green' : room?.status === 'ongoing' ? 'badge-gold' : 'badge-purple'}`}>
                {room?.status === 'waiting' ? 'Waiting' : room?.status === 'ongoing' ? 'Live' : 'Completed'}
              </span>
            </div>
            <p className="text-sm text-slate-400">{status}</p>
          </div>
          <div className="flex gap-2">
            <button onClick={() => navigate('/')} className="btn-secondary btn-sm">← Lobby</button>
          </div>
        </div>

        {/* Draw offer modal */}
        {drawOfferReceived && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm animate-fade-in">
            <div className="bg-navy-800 border border-navy-700/50 rounded-2xl shadow-2xl p-6 max-w-sm w-full animate-scale-in">
              <div className="text-center">
                <div className="text-5xl mb-3">🤝</div>
                <h3 className="text-lg font-bold text-white mb-2">Draw Offered</h3>
                <p className="text-sm text-slate-400 mb-5">Your opponent is offering a draw.</p>
                <div className="flex gap-3">
                  <button onClick={() => handleDrawResponse(false)} className="btn-secondary flex-1">Decline</button>
                  <button onClick={() => handleDrawResponse(true)} className="btn-primary flex-1">Accept Draw</button>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Mobile tabs */}
        <div className="lg:hidden flex gap-1 bg-navy-800/50 rounded-xl p-1 mb-4">
          {['board', 'moves', 'bracket', 'info'].map((tab) => (
            <button key={tab} onClick={() => setActiveTab(tab)}
              className={`flex-1 py-2 px-3 rounded-lg text-xs font-medium capitalize transition-all ${
                activeTab === tab ? 'bg-chess-green/15 text-chess-green' : 'text-slate-400 hover:text-white'
              }`}
            >
              {tab === 'board' ? '♟️ Board' : tab === 'moves' ? '📝 Moves' : tab === 'bracket' ? '🏆 Bracket' : 'ℹ️ Info'}
            </button>
          ))}
        </div>

        <div className="grid lg:grid-cols-12 gap-6">
          {/* Move History Column */}
          <div className={`lg:col-span-3 ${activeTab !== 'moves' ? 'hidden lg:block' : ''}`}>
            {match && <MoveHistory moves={moveHistory} currentIndex={previewIndex} onClickMove={handleMoveClick} />}
            {gameStatus === 'playing' && currentPlayerColor && (
              <div className="mt-4">
                <MatchOptions
                  onResign={handleResign}
                  onDrawOffer={handleDrawOffer}
                  onEmojiReaction={handleEmojiReaction}
                  onToggleSound={() => {
                    const ns = { ...settings, moveSound: !settings.moveSound };
                    setSettings(ns);
                    localStorage.setItem('chess-settings', JSON.stringify(ns));
                  }}
                  onFlipBoard={handleFlipBoard}
                  onOpenSettings={() => setShowSettings(true)}
                  soundEnabled={settings.moveSound !== false}
                  drawOfferPending={drawOfferPending}
                />
              </div>
            )}
          </div>

          {/* Board */}
          <div className={`lg:col-span-6 ${activeTab !== 'board' ? 'hidden lg:block' : ''}`}>
            <div className="card">
              {room?.status === 'completed' && !match ? (
                <div className="flex flex-col items-center justify-center gap-4 py-20 animate-fade-in">
                  <div className="text-6xl mb-2">🏆</div>
                  <h2 className="text-2xl font-bold text-white">Tournament Ended</h2>
                  <p className="text-slate-400 text-center max-w-sm">Check the <strong>Bracket</strong> for results!</p>
                </div>
              ) : match ? (
                <ChessBoard
                  roomId={roomId}
                  matchId={matchRef.current?.matchId}
                  fen={displayFen}
                  onMove={handleMove}
                  onPlayerReady={handlePlayerReady}
                  onSetPremove={handleSetPremove}
                  onCancelPremove={handleCancelPremove}
                  currentPlayer={previewIndex === -1 ? currentPlayer : null}
                  whitePlayer={whitePlayer}
                  blackPlayer={blackPlayer}
                  isSpectator={isSpectator || previewIndex !== -1}
                  gameStatus={previewIndex !== -1 ? 'preview' : gameStatus}
                  boardOrientation={boardOrientation}
                  timerData={timerData}
                  spectatorCount={spectatorCount}
                  floatingEmoji={floatingEmoji}
                  lastMove={lastMove}
                  settings={settings}
                  moveTimeoutMs={moveTimeoutMs}
                />
              ) : (
                <div className="flex flex-col items-center justify-center gap-4 py-20">
                  <div className="w-16 h-16 rounded-full bg-navy-700/50 flex items-center justify-center">
                    <div className="w-8 h-8 border-2 border-chess-green border-t-transparent rounded-full animate-spin" />
                  </div>
                  <p className="text-slate-400 text-sm">{room?.status === 'waiting' ? 'Waiting for players...' : 'Match pairing in progress...'}</p>
                  <p className="text-slate-500 text-xs">{room?.players?.length || 0}/{room?.maxPlayers || 0} players</p>
                </div>
              )}

              {previewIndex !== -1 && match && (
                <div className="mt-2 p-2 rounded-lg bg-sky-500/10 border border-sky-500/20 flex items-center justify-between">
                  <p className="text-xs text-sky-400">📖 Previewing move {previewIndex + 1} of {moveHistory.length}</p>
                  <button onClick={() => setPreviewIndex(-1)} className="text-xs text-sky-400 font-bold hover:text-sky-300">← Back to Live</button>
                </div>
              )}
            </div>
          </div>

          {/* Right Sidebar */}
          <div className={`lg:col-span-3 space-y-4 ${activeTab !== 'bracket' && activeTab !== 'info' ? 'hidden lg:block' : ''}`}>
            <div className={`card ${activeTab === 'info' ? 'hidden lg:block' : ''}`}>
              <h3 className="text-sm font-bold text-slate-300 mb-4 flex items-center gap-2"><span className="text-chess-green">🏆</span> Tournament Bracket</h3>
              <Bracket bracketData={bracket} currentUserId={user?.id} />
            </div>

            <div className={`card ${activeTab === 'bracket' ? 'hidden lg:block' : ''}`}>
              <h3 className="text-sm font-bold text-slate-300 mb-4">Contest Info</h3>
              <div className="space-y-3 text-sm">
                <div className="flex justify-between"><span className="text-slate-500">Entry Fee</span><span className="text-white font-semibold">₹{room?.entryFee || 0}</span></div>
                <div className="flex justify-between"><span className="text-slate-500">Prize Pool</span><span className="text-gold-400 font-bold">₹{((room?.entryFee || 0) * (room?.players?.length || 0)).toLocaleString()}</span></div>
                <div className="flex justify-between"><span className="text-slate-500">Players</span><span className="text-white font-semibold">{room?.players?.length || 0}/{room?.maxPlayers || 0}</span></div>
                <div className="flex justify-between"><span className="text-slate-500">Round</span><span className="text-white font-semibold">{room?.currentRound || 1}</span></div>
                <div className="border-t border-navy-700/30 pt-3 flex justify-between">
                  <span className="text-slate-500">Prize</span>
                  <span className={room?.prizeDistribution === 'winnerTA' ? 'badge-gold' : 'badge-blue'}>
                    {room?.prizeDistribution === 'winnerTA' ? 'Winner Takes All' : 'Top 4'}
                  </span>
                </div>
              </div>
            </div>

            <div className={`card ${activeTab === 'bracket' ? 'hidden lg:block' : ''}`}>
              <h3 className="text-sm font-bold text-slate-300 mb-4">Players</h3>
              <div className="space-y-2">{room?.players?.map((p, idx) => renderPlayerBadge(p, idx))}</div>
            </div>
          </div>
        </div>
      </div>

      {/* Result Modal */}
      {resultData && (
        <ResultModal
          result={resultData}
          onClose={() => setResultData(null)}
          onBackToLobby={() => navigate('/')}
          onPlayAgain={handlePlayAgain}
          onGameReview={reviewData ? () => { setResultData(null); setShowGameReview(true); } : null}
        />
      )}

      {/* Game Review Modal */}
      {showGameReview && reviewData && (
        <GameReview
          moves={moveSansRef.current}
          review={reviewData}
          playerColor={currentPlayerColor === 'white' ? 'w' : 'b'}
          onClose={() => setShowGameReview(false)}
        />
      )}

      {/* Settings Modal */}
      {showSettings && (
        <MatchSettings
          onClose={() => setShowSettings(false)}
          onApply={handleApplySettings}
        />
      )}
    </div>
  );
}
